import { useState } from "react";
import { raiseIssue } from "../../api/issuesApi";
import { raiseECComplaint } from "../../api/electionsApi";

function RaiseIssue() {
  const [description, setDescription] = useState("");
  const [type, setType] = useState("PUBLIC"); // PUBLIC or EC

  const submit = async () => {
    if (!description.trim()) {
      alert("Please describe the issue");
      return;
    }

    try {
      if (type === "PUBLIC") {
        await raiseIssue({ description });
        alert("Issue raised successfully");
      } else {
        await raiseECComplaint({ message: description });
        alert("Complaint sent to Election Commission");
      }

      setDescription("");
    } catch (err) {
      alert("Something went wrong");
      console.error(err);
    }
  };

  return (
    <div>
      <h2>Raise an Issue</h2>

      <label>Issue Type</label>
      <br />
      <select value={type} onChange={e => setType(e.target.value)}>
        <option value="PUBLIC">Public Issue (Visible to Constituency)</option>
        <option value="EC">Complaint to Election Commission</option>
      </select>

      <br /><br />

      <label>Description</label>
      <br />
      <textarea
        placeholder="Describe the issue clearly"
        value={description}
        onChange={e => setDescription(e.target.value)}
        rows={6}
        cols={50}
      />

      <br /><br />

      <button onClick={submit}>Submit</button>
    </div>
  );
}

export default RaiseIssue;
